{"tool":"newFileCreated","path":"frontend/src/components/MasterPanel.jsx","content":"@@ -0,0 +1,401 @@
+import React, { useState, useEffect } from 'react';
+import { Plus, Trash2, Link } from 'lucide-react';
+import { emitRefresh } from '../utils/events';
+
+const MasterPanel = ({ user }) => {
+  const [operators, setOperators] = useState([]);
+  const [assignments, setAssignments] = useState([]);
+  const [showAddOp, setShowAddOp] = useState(false);
+  const [showAssign, setShowAssign] = useState(false);
+  const [opForm, setOpForm] = useState({ name: '', phone: '' });
+  const [selectedOperator, setSelectedOperator] = useState('');
+  const [selectedMachines, setSelectedMachines] = useState([]);
+  const [shiftType, setShiftType] = useState('KUNDUZ');
+  const [restingToday, setRestingToday] = useState([]);
+
+  const token = localStorage.getItem('token');
+  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
+  const API = `http://${window.location.hostname}:8000`;
+
+  const fetchData = async () => {
+    try {
+      const [opsRes, asgRes, restRes] = await Promise.all([
+        fetch(`${API}/operators`, { headers }),
+        fetch(`${API}/assignments`, { headers }),
+        fetch(`${API}/rest-days/today`, { headers }),
+      ]);
+      if (opsRes.ok) setOperators(await opsRes.json());
+      if (asgRes.ok) setAssignments(await asgRes.json());
+      if (restRes.ok) setRestingToday(await restRes.json());
+    } catch (e) {}
+  };
+
+  useEffect(() => { fetchData(); }, []);
+  useEffect(() => { const h = () => fetchData(); window.addEventListener('app-refresh', h); return () => window.removeEventListener('app-refresh', h); }, []);
+
+  const handleAddOperator = async () => {
+    if (!opForm.name) return;
+    try {
+      const res = await fetch(`${API}/operators`, {
+        method: 'POST', headers, body: JSON.stringify(opForm)
+      });
+      if (res.ok) {
+        setOpForm({ name: '', phone: '' });
+        setShowAddOp(false);
+        fetchData();
+        emitRefresh();
+      }
+    } catch (e) {}
+  };
+
+  const handleDeleteOperator = async (id) => {
+    if (!confirm('Operatorni ochirmoqchimisiz?')) return;
+    try {
+      await fetch(`${API}/operators/${id}`, { method: 'DELETE', headers });
+      fetchData();
+      emitRefresh();
+    } catch (e) {}
+  };
+
+  const toggleMachine = (id) => {
+    setSelectedMachines(prev =>
+      prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]
+    );
+  };
+
+  const handleAssign = async () => {
+    if (!selectedOperator || selectedMachines.length === 0) return;
+    try {
+      const res = await fetch(`${API}/assignments`, {
+        method: 'POST', headers,
+        body: JSON.stringify({
+          operator_id: parseInt(selectedOperator),
+          machine_ids: selectedMachines,
+          shift_type: shiftType
+        })
+      });
+      if (res.ok) {
+        setSelectedOperator('');
+        setSelectedMachines([]);
+        setShowAssign(false);
+        fetchData();
+        emitRefresh();
+      }
+    } catch (e) {}
+  };
+
+  const handleUnassign = async (id) => {
+    try {
+      await fetch(`${API}/assignments/${id}`, { method: 'DELETE', headers });
+      fetchData();
+      emitRefresh();
+    } catch (e) {}
+  };
+
+  const isResting = (opId) => restingToday.some(r => r.operator_id === opId);
+
+  const kunduzAssignments = assignments.filter(a => a.shift_type === 'KUNDUZ');
+  const tungiAssignments = assignments.filter(a => a.shift_type === 'TUNGI');
+
+  const allMachineIds = Array.from({ length: 68 }, (_, i) => `S${i + 1}`);
+
+  const getAssignedOperator = (machineId, shift) => {
+    const a = assignments.find(a => a.machine_id === machineId && a.shift_type === shift && a.is_active === 1);
+    return a ? a : null;
+  };
+
+  return (
+    <div style={{ padding: '1.5rem' }}>
+      {restingToday.length > 0 && (
+        <div style={{
+          background: 'rgba(251, 191, 36, 0.1)',
+          border: '1px solid rgba(251, 191, 36, 0.3)',
+          borderRadius: '16px', padding: '1rem 1.5rem', marginBottom: '1.5rem',
+          display: 'flex', alignItems: 'center', gap: '12px'
+        }}>
+          <span style={{ fontSize: '1.5rem' }}>🛏️</span>
+          <div>
+            <div style={{ fontSize: '0.7rem', fontWeight: 700, color: '#fbbf24', textTransform: 'uppercase', letterSpacing: '1px' }}>
+              Bugun dam olganlar
+            </div>
+            <div style={{ fontSize: '1rem', color: '#fde68a', fontWeight: 700, marginTop: '2px' }}>
+              {restingToday.map(r => r.operator_name).join(', ')}
+            </div>
+          </div>
+        </div>
+      )}
+
+      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
+        <h2 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Master Panel</h2>
+        <div style={{ display: 'flex', gap: '8px' }}>
+          <button onClick={() => { setShowAddOp(!showAddOp); setShowAssign(false); }} style={btnStyle('var(--primary)')}>
+            <Plus size={16} /> Operator
+          </button>
+          <button onClick={() => { setShowAssign(!showAssign); setShowAddOp(false); }} style={btnStyle('#a855f7')}>
+            <Link size={16} /> Biriktirish
+          </button>
+        </div>
+      </div>
+
+      {showAddOp && (
+        <div style={formCardStyle}>
+          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Yangi Operator</h3>
+          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
+            <div>
+              <label style={labelStyle}>Ism</label>
+              <input className="input-field" style={inputSmStyle}
+                value={opForm.name} onChange={e => setOpForm({ ...opForm, name: e.target.value })}
+                placeholder="Operator ismi" />
+            </div>
+            <div>
+              <label style={labelStyle}>Telefon</label>
+              <input className="input-field" style={inputSmStyle}
+                value={opForm.phone} onChange={e => setOpForm({ ...opForm, phone: e.target.value })}
+                placeholder="+998..." />
+            </div>
+          </div>
+          <div style={{ display: 'flex', gap: '8px', marginTop: '0.5rem' }}>
+            <button onClick={handleAddOperator} style={btnStyle('var(--primary)')}>Saqlash</button>
+            <button onClick={() => setShowAddOp(false)} style={btnStyleSecondary()}>Bekor</button>
+          </div>
+        </div>
+      )}
+
+      {showAssign && (
+        <div style={formCardStyle}>
+          <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem', fontWeight: 700 }}>Operatorni Stanokka Biriktirish</h3>
+          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
+            <div>
+              <label style={labelStyle}>Operator</label>
+              <select className="input-field" style={inputSmStyle}
+                value={selectedOperator}
+                onChange={e => setSelectedOperator(e.target.value)}>
+                <option value="">Tanlang...</option>
+                {operators.filter(o => o.is_active).map(o => (
+                  <option key={o.id} value={o.id}>{o.name}</option>
+                ))}
+              </select>
+            </div>
+            <div>
+              <label style={labelStyle}>Smena</label>
+              <div style={{ display: 'flex', gap: '4px', marginTop: '4px' }}>
+                <button onClick={() => setShiftType('KUNDUZ')} style={{
+                  flex: 1, padding: '10px', borderRadius: '8px', border: 'none', cursor: 'pointer',
+                  fontWeight: 700, fontSize: '0.8rem',
+                  background: shiftType === 'KUNDUZ' ? '#f59e0b' : 'rgba(255,255,255,0.05)',
+                  color: shiftType === 'KUNDUZ' ? '#000' : 'var(--text-muted)'
+                }}>☀️ Kunduzgi</button>
+                <button onClick={() => setShiftType('TUNGI')} style={{
+                  flex: 1, padding: '10px', borderRadius: '8px', border: 'none', cursor: 'pointer',
+                  fontWeight: 700, fontSize: '0.8rem',
+                  background: shiftType === 'TUNGI' ? '#6366f1' : 'rgba(255,255,255,0.05)',
+                  color: shiftType === 'TUNGI' ? '#fff' : 'var(--text-muted)'
+                }}>🌙 Tungi</button>
+              </div>
+            </div>
+          </div>
+
+          <label style={labelStyle}>Stanoklarni tanlang ({selectedMachines.length} ta tanlandi)</label>
+          <div style={{
+            display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(55px, 1fr))',
+            gap: '6px', marginTop: '8px', maxHeight: '300px', overflowY: 'auto',
+            padding: '12px', background: 'rgba(0,0,0,0.3)', borderRadius: '12px'
+          }}>
+            {allMachineIds.map(id => {
+              const isSelected = selectedMachines.includes(id);
+              const assignedK = getAssignedOperator(id, 'KUNDUZ');
+              const assignedT = getAssignedOperator(id, 'TUNGI');
+              const isTaken = shiftType === 'KUNDUZ' ? assignedK : assignedT;
+              return (
+                <button key={id} onClick={() => !isTaken && toggleMachine(id)} style={{
+                  padding: '8px 4px', borderRadius: '8px', border: '2px solid',
+                  borderColor: isSelected ? '#a855f7' : isTaken ? '#ef4444' : 'rgba(255,255,255,0.1)',
+                  background: isSelected ? 'rgba(168,85,247,0.2)' : isTaken ? 'rgba(239,68,68,0.1)' : 'rgba(255,255,255,0.03)',
+                  color: isSelected ? '#a855f7' : isTaken ? '#ef4444' : 'var(--text-main)',
+                  cursor: isTaken ? 'not-allowed' : 'pointer',
+                  fontWeight: 700, fontSize: '0.7rem', opacity: isTaken ? 0.6 : 1
+                }}>
+                  {id}
+                  {isTaken && <div style={{ fontSize: '0.5rem', marginTop: '2px', color: '#ef4444' }}>{isTaken.operator_name?.substring(0, 6)}</div>}
+                </button>
+              );
+            })}
+          </div>
+
+          <div style={{ display: 'flex', gap: '8px', marginTop: '1rem' }}>
+            <button onClick={handleAssign} style={btnStyle('#a855f7')}>
+              Biriktirish ({selectedMachines.length} ta)
+            </button>
+            <button onClick={() => { setShowAssign(false); setSelectedMachines([]); }} style={btnStyleSecondary()}>Bekor</button>
+          </div>
+        </div>
+      )}
+
+      {/* Kunduzgi smena */}
+      <div style={{ marginBottom: '2rem' }}>
+        <h3 style={{ fontSize: '1.1rem', fontWeight: 800, color: '#f59e0b', marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
+          ☀️ Kunduzgi Smena
+        </h3>
+        <div style={tableCardStyle}>
+          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
+            <thead>
+              <tr style={{ borderBottom: '1px solid var(--panel-border)' }}>
+                <th style={thStyle}>Operator</th>
+                <th style={thStyle}>Telefon</th>
+                <th style={thStyle}>Biriktirilgan Stanoklar</th>
+                <th style={thStyle}>Status</th>
+                <th style={thStyle}>Amallar</th>
+              </tr>
+            </thead>
+            <tbody>
+              {operators.map(op => {
+                const opAsgs = kunduzAssignments.filter(a => a.operator_id === op.id && a.is_active === 1);
+                const resting = isResting(op.id);
+                if (opAsgs.length === 0) return null;
+                return (
+                  <tr key={op.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
+                    <td style={tdStyle}>
