+const InteractiveMap = ({ machines, onSelectMachine, user, selectedMachine }) => {
+
+  // ═══ KATTA SEX - ongdan chapga, sex ichida ═══
+  const generateMainBlock = () => {
+    const nodes = [];
+    const w = 44, h = 32;
+    const gapX = 65;
+    const gapY = 70;
+    const roomRight = 720;
+    const roomTop = 280;
+
+    // 1-49: 5 ta qator (10,10,10,10,9) - ongdan chapga raqamlash
+    const rowCounts1 = [10, 10, 10, 10, 9];
+    let id = 1;
+    rowCounts1.forEach((count, rowIdx) => {
+      const rowWidth = count * gapX;
+      const startX = roomRight - rowWidth;
+      const y = roomTop + rowIdx * gapY;
+      // Ongdan chapga: oxirgi raqam o'ngda, birinchi raqam chapda
+      for (let i = count - 1; i >= 0; i--) {
+        nodes.push({ id: id++, x: startX + i * gapX, y, w, h });
+      }
+    });
+
+    // 50-60: 2 ta qator (6, 5) - ongdan chapga raqamlash
+    const rowCounts2 = [6, 5];
+    rowCounts2.forEach((count, rowIdx) => {
+      const rowWidth = count * gapX;
+      const startX = roomRight - rowWidth;
+      const y = roomTop + (5 + rowIdx) * gapY;
+      for (let i = count - 1; i >= 0; i--) {
+        nodes.push({ id: id++, x: startX + i * gapX, y, w, h });
+      }
+    });
+
+    return nodes;
+  };
+
+  // ═══ KICHKINA SEX - 61-68, yuqoridan pastga ═══
+  const generateRightBlock = () => {
+    const nodes = [];
+    const w = 44, h = 32;
+    const startX = 870;
+    const startY = 80;
+    const gapY = 75;
+    for (let i = 0; i < 8; i++) {
+      nodes.push({ id: 61 + i, x: startX, y: startY + i * gapY, w, h });
+    }
+    return nodes;
+  };
+
+  const allNodes = [...generateMainBlock(), ...generateRightBlock()];
+
+  const walls = [
+    { x1: 30, y1: 30, x2: 960, y2: 30 },
+    { x1: 30, y1: 30, x2: 30, y2: 760 },
+    { x1: 960, y1: 30, x2: 960, y2: 760 },
+    { x1: 30, y1: 760, x2: 960, y2: 760 },
+    { x1: 280, y1: 30, x2: 280, y2: 230 },
+    { x1: 30, y1: 230, x2: 720, y2: 230 },
+    { x1: 720, y1: 30, x2: 720, y2: 760 },
+    { x1: 30, y1: 500, x2: 180, y2: 760 },
+  ];
+
+  return (
+    <div className="factory-bg">
+      <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
+        {walls.map((w, i) => (
+          <line key={`w${i}`} x1={w.x1} y1={w.y1} x2={w.x2} y2={w.y2}
+            stroke="#475569" strokeWidth="2" />
+        ))}
+      </svg>
+
+      <div style={{ position: 'absolute', left: 80, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>XOMASHYO OMBORI</div>
+      <div style={{ position: 'absolute', left: 380, top: 110, color: '#64748b', fontSize: '0.75rem', fontWeight: 700, letterSpacing: '2px', textTransform: 'uppercase' }}>IP YIGIRUV XONASI</div>
+
+      {[200, 500, 800].map((x, i) => (
+        <div key={`exit${i}`} style={{
+          position: 'absolute', left: x, top: 10,
+          background: '#22c55e', padding: '4px 14px', borderRadius: '6px',
+          fontSize: '0.65rem', fontWeight: 800, color: '#064e3b',
+          boxShadow: '0 0 10px rgba(34,197,94,0.3)'
+        }}>▲ CHIQISH</div>
+      ))}
+
+      {allNodes.map((node) => {
+        const machineData = machines.find((m) => m.id === `S${node.id}`) || { baud: 0, remaining: 0, status: 'OFFLINE' };
+        const isConnected = machineData.baud > 0;
+
+        let statusClass = 'stopped';
+        let statusMsg = "ESP32 OFF (Aloqa yo'q)";
+
+        if (machineData.status === 'OFFLINE') {
+          statusClass = 'stopped';
+          statusMsg = "ESP32 OFF (Aloqa yo'q)";
+        } else if (machineData.status === 'ESP_ONLINE_NO_SIGNAL') {
+          statusClass = 'searching';
+          statusMsg = "ESP32 ONLINE | RS485 SIGNAL YO'Q";
+        } else if (machineData.status === 'ASNOVA_EMPTY') {
+          statusClass = 'warning';
+          statusMsg = "STOP (Asnova tugadi)";
+        } else if (machineData.status === 'RUNNING') {
+          statusClass = 'running';
+          statusMsg = "ISHLAYAPTI";
+        }
+
+        const isRunning = statusClass === 'running';
+        const isFocused = selectedMachine?.id === `S${node.id}`;
+
+        return (
+          <div
+            key={node.id}
+            className={`machine-node ${statusClass} ${isRunning ? 'pulse-neon' : ''} ${isFocused ? 'is-focused' : ''}`}
+            style={{ left: `${node.x}px`, top: `${node.y}px`, width: `${node.w}px`, height: `${node.h}px` }}
+            onClick={() => onSelectMachine({ ...machineData, displayStatus: statusMsg, id: `S${node.id}` })}
+            title={`S${node.id} | ${statusMsg}`}
+          >
+            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1px', position: 'relative' }}>
+              {isFocused && <div className="smart-pulse"></div>}
+              <svg width="22" height="16" viewBox="0 0 24 24" fill="currentColor"
+                style={{ opacity: isConnected ? 1 : 0.35 }}>
+                <path d="M2,14 L2,18 L22,18 L22,14 M4,14 L4,6 L20,6 L20,14 M6,10 L18,10 M2,8 L2,20 L22,20 L22,8 L20,8 L20,4 L4,4 L4,8 Z" />
+                <rect x="7" y="11" width="10" height="3"
+                  opacity={isRunning ? 0.9 : 0.15}
+                  className={isRunning ? 'shuttle-anim' : ''} />
+              </svg>
+              <span style={{ fontSize: '0.55rem', letterSpacing: '0.5px', fontWeight: 800, lineHeight: 1 }}>
+                {node.id}
+              </span>
+            </div>
+          </div>
+        );
+      })}
+    </div>
+  );
+};
+
+export default InteractiveMap;

