+        {visibleTabs.map(tab => (
+          <button
+            key={tab.id}
+            onClick={() => onTabChange(tab.id)}
+            style={{
+              display: 'flex',
+              alignItems: 'center',
+              gap: '10px',
+              padding: '10px 14px',
+              borderRadius: '10px',
+              border: 'none',
+              cursor: 'pointer',
+              fontSize: '0.85rem',
+              fontWeight: 600,
+              background: activeTab === tab.id ? 'rgba(0, 210, 255, 0.15)' : 'transparent',
+              color: activeTab === tab.id ? 'var(--primary)' : 'var(--text-muted)',
+              transition: 'all 0.2s',
+              textAlign: 'left',
+            }}
+          >
+            {tab.icon}
+            {tab.label}
+          </button>
+        ))}
+      </nav>
+
+      <div style={{ padding: '1rem', background: 'rgba(255,255,255,0.03)', borderRadius: '16px', marginTop: '1rem' }}>
+        <div style={{ marginBottom: '0.75rem' }}>
+          <p style={{ margin: 0, fontSize: '0.9rem', fontWeight: 600 }}>{user?.full_name}</p>
+          <p style={{ margin: 0, fontSize: '0.7rem', color: 'var(--text-muted)' }}>{user?.role}</p>
+        </div>
+        <button
+          onClick={onLogout}
+          style={{
+            width: '100%',
+            padding: '8px',
+            fontSize: '0.8rem',
+            background: '#ef444422',
+            color: '#ef4444',
+            border: '1px solid #ef444444',
+            borderRadius: '8px',
+            cursor: 'pointer',
+            fontWeight: 600,
+            display: 'flex',
+            alignItems: 'center',
+            justifyContent: 'center',
+            gap: '6px'
+          }}
+        >
+          <LogOut size={14} /> Chiqish
+        </button>
+      </div>
+    </div>
+  );
+};
+
+export default Sidebar;

