+import React, { useState, useEffect } from 'react';
+import { Plus, Trash2, Edit2, Save, X } from 'lucide-react';
+
+const AdminPanel = ({ user }) => {
+  const [users, setUsers] = useState([]);
+  const [showForm, setShowForm] = useState(false);
+  const [editId, setEditId] = useState(null);
+  const [form, setForm] = useState({ username: '', password: '', full_name: '', role: 'MASTER' });
+  const [error, setError] = useState('');
+
+  const token = localStorage.getItem('token');
+  const headers = { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' };
+  const API = `http://${window.location.hostname}:8000`;
+
+  const roleColors = { ADMIN: '#ef4444', MASTER: '#3b82f6', NAZORATCHI: '#22c55e', MECHANIC: '#f59e0b' };
+
+  const fetchUsers = async () => {
+    try {
+      const res = await fetch(`${API}/users`, { headers });
+      if (res.ok) setUsers(await res.json());
+    } catch (e) {}
+  };
+
+  useEffect(() => { fetchUsers(); }, []);
+
+  const resetForm = () => {
+    setForm({ username: '', password: '', full_name: '', role: 'MASTER' });
+    setShowForm(false);
+    setEditId(null);
+    setError('');
+  };
+
+  const handleCreate = async () => {
+    if (!form.username || !form.password || !form.full_name) {
+      setError('Barcha maydonlarni toldiring');
+      return;
+    }
+    try {
+      const res = await fetch(`${API}/users`, {
+        method: 'POST', headers, body: JSON.stringify(form)
+      });
+      if (res.ok) {
+        fetchUsers();
+        resetForm();
+      } else {
+        const data = await res.json();
+        setError(data.detail || 'Xatolik');
+      }
+    } catch (e) { setError('Server xatoligi'); }
+  };
+
+  const handleUpdate = async () => {
+    const body = { full_name: form.full_name, role: form.role };
+    if (form.password) body.password = form.password;
+    try {
+      const res = await fetch(`${API}/users/${editId}`, {
+        method: 'PUT', headers, body: JSON.stringify(body)
+      });
+      if (res.ok) {
+        fetchUsers();
+        resetForm();
+      }
+    } catch (e) { setError('Server xatoligi'); }
+  };
+
+  const handleDelete = async (id) => {
+    if (!confirm('Rostdan ham ochirmoqchimisiz?')) return;
+    try {
+      await fetch(`${API}/users/${id}`, { method: 'DELETE', headers });
+      fetchUsers();
+    } catch (e) {}
+  };
